// Optionally set batchId before running the workflow.
// Leave as null to complete the latest batch that is still Processing.
const batchId = null;

return [{
  json: {
    batch_id: batchId,
  },
}];

const rawBatchId = $input.first()?.json?.batch_id;
const batchId = rawBatchId === null || rawBatchId === undefined || rawBatchId === ''
  ? null
  : Number(rawBatchId);

if (batchId !== null && (!Number.isInteger(batchId) || batchId <= 0)) {
  return [{
    json: {
      batch_id: rawBatchId,
      completeBatchSql: "select NULL::bigint as requested_batch_id, NULL::bigint as batch_id, 0::bigint as completed_signup_count, 'batch_id must be a positive integer when provided'::text as message;",
    },
  }];
}

const requestedBatchSql = batchId === null ? 'NULL' : `${batchId}::bigint`;
const selectedBatchSql = batchId === null
  ? "select id from signup_batches where status = 'Processing' order by id desc limit 1"
  : `select ${batchId}::bigint as id`;

return [{
  json: {
    batch_id: batchId,
    completeBatchSql: `with selected_batch as (
    ${selectedBatchSql}
),
updated_signups as (
    update member_signups
    set status = 'Complete'
    where batch_id = (select id from selected_batch)
      and status = 'Processing'
    returning id
),
updated_batch as (
    update signup_batches
    set status = 'Complete',
        completed_at = now()
    where id = (select id from selected_batch)
      and status = 'Processing'
    returning id
)
select
    ${requestedBatchSql} as requested_batch_id,
    (select id from updated_batch) as batch_id,
    coalesce((select count(*) from updated_signups), 0) as completed_signup_count,
    case
        when exists (select 1 from updated_batch) then 'Complete'
        when exists (select 1 from selected_batch) then 'Batch not found or already complete'
        else 'No processing batch found'
    end as message;`,
  },
}];
